# process-wide cache: pricing lookups are expensive (a downstream rate-card
# API call) so we memoize by product id for the lifetime of the worker
_PRICING_CACHE: dict[str, float] = {}

def get_price(product_id: str) -> float:
    if product_id in _PRICING_CACHE:
        return _PRICING_CACHE[product_id]
    price = _fetch_negotiated_price(product_id)
    _PRICING_CACHE[product_id] = price
    return price

def quote_handler(request):
    tenant_id = request.headers['X-Tenant-Id']
    product_id = request.json['product_id']
    # get_price is not passed tenant_id — negotiated/custom pricing is per tenant
    price = get_price(product_id)
    return {'price': price}
